tactic:
let φ : G →* (ι →ᵤ M) :=
  { toFun := swap ((↑) ∘ F)
    map_one' := by dsimp [UniformFun]; ext; exact map_one _
    map_mul' := fun a b => by dsimp [UniformFun]; ext; exact map_mul _ _ _ }

let f : @MonoidHom M M m₁.toMulOneClass m₂.toMulOneClass :=
  @MonoidHom.mk _ _ (_) _ (@OneHom.mk _ _ (_) _ id h₁)
    (fun x y => congr_fun (congr_fun h_mul x) y)

let e : B₁ ≃ₐ[A₂] B₂ :=
  { e₂ with
    commutes' := fun r ↦ by
      simpa [RingHom.algebraMap_toAlgebra] using DFunLike.congr_fun he.symm (e₁.symm r) }
